// SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
// SPDX-License-Identifier: Apache-2.0
//
// Reproduction: NVIDIA API key exposed in process list.
// The `run` helper wraps commands in `bash -c`, which makes the API key visible
// in `ps aux` output.  This test verifies that the API key does NOT appear in
// the command string passed to the shell.

const fs = require("node:fs");
const path = require("node:path");
const os = require("node:os");
const childProcess = require("node:child_process");
const { spawnSync } = childProcess;

// Load the actual shellQuote helper so we can construct the same command
// string that the production code builds.
const { shellQuote } = require("../bin/lib/runner");

const FAKE_KEY = "nvapi-abc123secret456xyz789";

describe("API key exposure via command line", () => {
  /**
   * Simulate what happens when onboard.js passes the API key as a
   * `--credential` value through `bash -c`.  The test runs a child that
   * prints its own /proc/self/cmdline so we can check whether the key is
   * visible there.
   */
  it("exposes key in bash -c command string (current behavior)", () => {
    // Build the command the same way the production code does today.
    const unsafeCmd =
      `openshell provider create --name nvidia-nim --type openai ` +
      `--credential ${shellQuote("NVIDIA_API_KEY=" + FAKE_KEY)} ` +
      `--config "OPENAI_BASE_URL=https://integrate.api.nvidia.com/v1"`;

    // Use a helper script that prints its own /proc/PID/cmdline.
    const inspector = path.join(os.tmpdir(), "nemoclaw-cmdline-inspector.sh");
    fs.writeFileSync(
      inspector,
      "#!/usr/bin/env bash\ncat /proc/self/cmdline | tr '\\0' ' '\necho\n",
      { mode: 0o700 },
    );

    // Patch openshell → inspector so the command runs our inspector instead.
    const tmpBin = fs.mkdtempSync(path.join(os.tmpdir(), "nemoclaw-test-bin-"));
    fs.symlinkSync(inspector, path.join(tmpBin, "openshell"));

    try {
      const result = spawnSync("bash", ["-c", unsafeCmd], {
        encoding: "utf-8",
        env: { ...process.env, PATH: `${tmpBin}:${process.env.PATH}` },
        timeout: 5000,
      });

      const cmdline = result.stdout || "";
      // The key MUST NOT appear in the process command line.
      // With the current (unsafe) code it WILL appear — this test documents
      // the vulnerability.  Once the fix is in place, the test should be
      // flipped to expect the key to NOT appear.
      //
      // For now this test proves the reproduction is accurate.
      expect(cmdline).toMatch(/nvapi-abc123secret456xyz789/);
    } finally {
      try { fs.unlinkSync(inspector); } catch {}
      try { fs.unlinkSync(path.join(tmpBin, "openshell")); } catch {}
      try { fs.rmdirSync(tmpBin); } catch {}
    }
  });

  /**
   * Verify that when we pass the credential via an environment variable
   * instead of the command line, the key does NOT appear in the process
   * command line.
   */
  it("does NOT expose key when passed via environment variable", () => {
    // This is the safe approach: set the credential in the environment
    // and tell openshell to read from env var name only.
    const safeCmd =
      `openshell provider create --name nvidia-nim --type openai ` +
      `--credential NVIDIA_API_KEY ` +
      `--config "OPENAI_BASE_URL=https://integrate.api.nvidia.com/v1"`;

    const inspector = path.join(os.tmpdir(), "nemoclaw-cmdline-inspector-env.sh");
    fs.writeFileSync(
      inspector,
      "#!/usr/bin/env bash\ncat /proc/self/cmdline | tr '\\0' ' '\necho\n",
      { mode: 0o700 },
    );

    const tmpBin = fs.mkdtempSync(path.join(os.tmpdir(), "nemoclaw-test-bin-env-"));
    fs.symlinkSync(inspector, path.join(tmpBin, "openshell"));

    try {
      const result = spawnSync("bash", ["-c", safeCmd], {
        encoding: "utf-8",
        env: {
          ...process.env,
          PATH: `${tmpBin}:${process.env.PATH}`,
          NVIDIA_API_KEY: FAKE_KEY,
        },
        timeout: 5000,
      });

      const cmdline = result.stdout || "";
      // The key must NOT appear — it's only in the environment, not on
      // the command line.
      expect(cmdline).not.toMatch(/nvapi-abc123secret456xyz789/);
    } finally {
      try { fs.unlinkSync(inspector); } catch {}
      try { fs.unlinkSync(path.join(tmpBin, "openshell")); } catch {}
      try { fs.rmdirSync(tmpBin); } catch {}
    }
  });
});

