// SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
// SPDX-License-Identifier: Apache-2.0
//
// Reproduction: NVIDIA API key exposed in process list.
// The `run` helper wraps commands in `bash -c`, which makes the API key visible
// in `ps aux` output.  This test verifies that the API key does NOT appear in
// the command string passed to the shell.

const path = require("node:path");
const childProcess = require("node:child_process");
const { spawnSync } = childProcess;

// Load the actual shellQuote helper so we can construct the same command
// string that the production code builds.
const { shellQuote } = require("../bin/lib/runner");

const FAKE_KEY = "nvapi-abc123secret456xyz789";

describe("API key exposure via command line", () => {
  /**
   * Simulate what happens when onboard.js passes the API key as a
   * `--credential` value through `bash -c`.  We use a Node.js child
   * that inspects its parent's cmdline to check whether the key is
   * visible in the process listing.
   */
  it("exposes key in bash -c command string (current behavior)", () => {
    // Build the command the same way the production code does today.
    const unsafeCmd =
      `echo SUBPROC_START && ` +
      `openshell provider create --name nvidia-nim --type openai ` +
      `--credential ${shellQuote("NVIDIA_API_KEY=" + FAKE_KEY)} ` +
      `--config "OPENAI_BASE_URL=https://integrate.api.nvidia.com/v1"`;

    // Run via bash -c (same as the `run` helper in production).
    // The bash process receives the entire command string, and on Linux
    // the full command (including the API key) is visible in /proc/PID/cmdline
    // and `ps aux` output.
    const result = spawnSync("bash", ["-c", unsafeCmd], {
      encoding: "utf-8",
      timeout: 5000,
      env: { ...process.env, PATH: process.env.PATH },
    });

    // bash -c itself displays the full command string in its cmdline.
    // We can verify this by checking that the parent bash process's
    // cmdline (which is our spawnSync call) contains the key.
    //
    // On Linux, the spawnSync spawns "bash" with args ["-c", unsafeCmd].
    // The key appears in argv[2] of the bash process — visible to ps.
    //
    // We verify the vulnerability by checking that the key is embedded
    // in the command that was executed.
    const fullCmd = result.stdout || "";
    // The bash process itself will have the key in its /proc/self/cmdline.
    // Since we can't inspect ourselves, we verify indirectly by confirming
    // the command DID contain the key — which would be visible to ps.
    expect(unsafeCmd).toMatch(/nvapi-abc123secret456xyz789/);
    // The command constructed for bash -c contains the actual key value.
    // This is the vulnerability: when this runs in production, any user
    // can see the key via `ps aux`.
  });

  /**
   * Verify that when we pass the credential via an environment variable
   * instead of the command line, the key does NOT appear in the process
   * command line.
   */
  it("does NOT expose key when passed via environment variable", () => {
    // This is the safe approach: the credential env var is set in the
    // child's environment, and the command line only references the env
    // var NAME (not the value).
    const safeCmd =
      `echo SUBPROC_START && ` +
      `openshell provider create --name nvidia-nim --type openai ` +
      `--credential NVIDIA_API_KEY ` +
      `--config "OPENAI_BASE_URL=https://integrate.api.nvidia.com/v1"`;

    const result = spawnSync("bash", ["-c", safeCmd], {
      encoding: "utf-8",
      timeout: 5000,
      env: {
        ...process.env,
        NVIDIA_API_KEY: FAKE_KEY,
      },
    });

    // The command line must NOT contain the key value — it's only
    // in the environment, which is NOT visible to `ps aux`.
    expect(safeCmd).not.toMatch(/nvapi-abc123secret456xyz789/);
    // The key is still available via environment to the child process.
  });
});

