// SPDX-License-Identifier: Apache-2.0
//
// Verify that NVIDIA_API_KEY is never interpolated into shell command
// strings where it would be visible to `ps aux` or /proc/PID/cmdline.
//
// The fix passes credentials via environment variables (inherited by
// child processes) instead of embedding them in shell command strings.

const path = require("node:path");
const childProcess = require("node:child_process");
const { spawnSync } = childProcess;

const FAKE_KEY = "nvapi-abc123secret456xyz789";

describe("API key exposure via command line", () => {
  /**
   * The credential is passed via the NVIDIA_API_KEY environment variable,
   * NOT embedded in the command string.  Verify the command line only
   * contains the env-var NAME, never the value.
   */
  it("does NOT expose API key in provider create command", () => {
    // This matches the fixed production code in bin/lib/onboard.js:
    //   --credential NVIDIA_API_KEY  (env-var name only)
    const safeCmd =
      `openshell provider create --name nvidia-nim --type openai ` +
      `--credential NVIDIA_API_KEY ` +
      `--config "OPENAI_BASE_URL=https://integrate.api.nvidia.com/v1"`;

    // The command string must NOT contain the API key value.
    expect(safeCmd).not.toMatch(/nvapi-abc123secret456xyz789/);

    // Run via bash -c (same as the `run` helper in production).
    const result = spawnSync("bash", ["-c", `echo ok && ${safeCmd} 2>/dev/null || true`], {
      encoding: "utf-8",
      timeout: 5000,
      env: {
        ...process.env,
        NVIDIA_API_KEY: FAKE_KEY,
      },
    });

    // The key is available to the child process via environment
    // but NEVER appears in the command line visible to `ps aux`.
    expect(result.status).toBe(0);
  });

  /**
   * Regression: the old code interpolated KEY=VALUE into the command.
   * Verify the old pattern is NOT present in the production source files.
   */
  it("does NOT embed API key value in --credential flag", () => {
    const fs = require("node:fs");
    const onboardSrc = fs.readFileSync(
      path.join(__dirname, "..", "bin", "lib", "onboard.js"),
      "utf-8",
    );

    // The old pattern `--credential ${shellQuote("NVIDIA_API_KEY=" + key)}`
    // must NOT appear in the source.
    expect(onboardSrc).not.toMatch(/NVIDIA_API_KEY=\$\{/);
  });

  /**
   * Verify nemoclaw.js setupSpark no longer passes the key on the
   * command line.
   */
  it("does NOT embed API key in setupSpark sudo command", () => {
    const fs = require("node:fs");
    const cliSrc = fs.readFileSync(
      path.join(__dirname, "..", "bin", "nemoclaw.js"),
      "utf-8",
    );

    // The old pattern `sudo -E NVIDIA_API_KEY=...` must NOT appear.
    expect(cliSrc).not.toMatch(/sudo -E NVIDIA_API_KEY=/);
  });
});

